import anthropic

client = anthropic.Anthropic()

# A function definition is a plain Python dict
search_products_tool = {
    "name": "search_products",
    "description": (
        "Search the product catalogue for items matching a text query. "
        "Returns a list of matching products with name, price, and stock status. "
        "Use this when the user wants to find or browse products."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "Search keywords, e.g. 'red running shoes size 10'"
            },
            "max_results": {
                "type": "integer",
                "description": "Maximum number of products to return (1-20). Defaults to 5.",
                "default": 5
            }
        },
        "required": ["query"]
    }
}

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=[search_products_tool],
    messages=[{"role": "user", "content": "I need waterproof hiking boots"}]
)

for block in response.content:
    if block.type == "tool_use":
        print(block.name)    # search_products
        print(block.input)   # {"query": "waterproof hiking boots", "max_results": 5}

def make_tool(name: str, description: str, properties: dict, required: list) -> dict:
    """Helper to build a well-formed tool definition."""
    return {
        "name": name,
        "description": description,
        "input_schema": {
            "type": "object",
            "properties": properties,
            "required": required
        }
    }

get_order_tool = make_tool(
    name="get_order",
    description=(
        "Retrieve the status and details of a customer order by its ID. "
        "Use when the user asks about an existing order."
    ),
    properties={
        "order_id": {
            "type": "string",
            "description": "The order ID, e.g. 'ORD-20241201-8842'"
        }
    },
    required=["order_id"]
)

cancel_order_tool = make_tool(
    name="cancel_order",
    description=(
        "Cancel an order that has not yet shipped. "
        "Only use this after confirming the user explicitly wants to cancel."
    ),
    properties={
        "order_id": {"type": "string", "description": "Order ID to cancel"},
        "reason": {
            "type": "string",
            "enum": ["changed_mind", "wrong_item", "duplicate_order", "other"],
            "description": "Cancellation reason"
        }
    },
    required=["order_id", "reason"]
)

tools = [get_order_tool, cancel_order_tool]

# The actual Python functions that implement each tool
def search_products(query: str, max_results: int = 5) -> list[dict]:
    """Execute the search against the real database."""
