def get_order(order_id: str) -> dict:
    order = orders_db.get(order_id)
    if not order:
        return {"error": f"Order {order_id} not found"}
    return order

def cancel_order(order_id: str, reason: str) -> dict:
    result = orders_db.cancel(order_id, reason)
    return {"cancelled": result.success, "refund_eta": result.refund_eta}

# Map tool name -> function (used by the dispatcher)
TOOL_REGISTRY: dict[str, callable] = {
    "search_products": search_products,
    "get_order":       get_order,
    "cancel_order":    cancel_order,
}

def dispatch(tool_use_block) -> str:
    fn = TOOL_REGISTRY.get(tool_use_block.name)
    if fn is None:
        return f"Unknown tool: {tool_use_block.name}"
    result = fn(**tool_use_block.input)
    return json.dumps(result)

def run_agent(user_message: str, tools: list[dict]) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages
        )

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        # Collect assistant message (may have mixed text + tool_use blocks)
        messages.append({"role": "assistant", "content": response.content})

        # Execute each tool_use block, collect results
        results = []
        for block in response.content:
            if block.type == "tool_use":
                output = dispatch(block)
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output
                })

        messages.append({"role": "user", "content": results})

# Example usage
answer = run_agent(
    "I need to cancel my order ORD-20241201-8842 because I changed my mind.",
    tools=[get_order_tool, cancel_order_tool]
)
print(answer)

