import inspect, typing

def python_type_to_json_schema(annotation) -> dict:
    """Convert a Python type annotation to a JSON Schema fragment."""
    origin = typing.get_origin(annotation)
    if annotation is str:
        return {"type": "string"}
    if annotation is int:
        return {"type": "integer"}
    if annotation is float:
        return {"type": "number"}
    if annotation is bool:
        return {"type": "boolean"}
    if annotation is list or origin is list:
        args = typing.get_args(annotation)
        item_schema = python_type_to_json_schema(args[0]) if args else {}
        return {"type": "array", "items": item_schema}
    return {"type": "string"}   # fallback

def build_tool_from_function(fn: callable, description: str) -> dict:
    """Auto-generate a tool definition from a function's signature."""
    sig = inspect.signature(fn)
    properties = {}
    required = []
    for name, param in sig.parameters.items():
        annotation = param.annotation
        if annotation is inspect.Parameter.empty:
            annotation = str
        prop = python_type_to_json_schema(annotation)
        # Use parameter default as description fallback
        prop["description"] = f"The {name.replace('_', ' ')}"
        properties[name] = prop
        if param.default is inspect.Parameter.empty:
            required.append(name)
    return {
        "name": fn.__name__,
        "description": description,
        "input_schema": {
            "type": "object",
            "properties": properties,
            "required": required
        }
    }

