def get_order(order_id: str) -> dict:
    order = orders_db.get(order_id)
    if not order:
        # Return error dict, not an exception — lets Claude report gracefully
        return {
            "error": "not_found",
            "message": f"No order with ID {order_id!r} found.",
            "hint": "Check that the order ID starts with ORD- and has no spaces."
        }
    return order.to_dict()

