import json, unittest

class TestToolDefinitions(unittest.TestCase):

    def test_required_keys_present(self):
        for tool in tools:
            self.assertIn("name", tool)
            self.assertIn("description", tool)
            self.assertIn("input_schema", tool)

    def test_required_params_subset_of_properties(self):
        for tool in tools:
            schema = tool["input_schema"]
            props = set(schema.get("properties", {}).keys())
            required = set(schema.get("required", []))
            self.assertTrue(required.issubset(props),
                f"{tool['name']}: required {required} not in properties {props}")

    def test_no_empty_descriptions(self):
        for tool in tools:
            self.assertTrue(len(tool["description"]) >= 20,
                f"{tool['name']}: description too short")
            schema = tool["input_schema"]
            for param_name, param_schema in schema.get("properties", {}).items():
                self.assertIn("description", param_schema,
                    f"{tool['name']}.{param_name}: missing description")

    def test_array_params_have_items(self):
        for tool in tools:
            for param_name, param_schema in tool["input_schema"].get("properties", {}).items():
                if param_schema.get("type") == "array":
                    self.assertIn("items", param_schema,
                        f"{tool['name']}.{param_name}: array missing items")

if __name__ == "__main__":
    unittest.main()
